(* ============================================================ *)
(* PROG_SAFETY: 안전 인터록 + Watchdog                         *)
(* 역할: PC 통신 감시, EMO 처리, 전출력 차단                    *)
(* 실행 순서: 가장 먼저 (PROG_IO_MAP, PROG_SERVO 보다 선행)     *)
(* ============================================================ *)

(* 1. 입력 읽기 *)
wHeartbeat := %MW500 AND 16#00FF;
bPcReady := %MW500.8;
bPcEmoReq := %MW500.9;
bEmoInput := %IX0.0.11;

(* 2. Watchdog 감시 — 500ms 무변화 시 통신 두절 *)
IF wHeartbeat <> g_WD_PrevCount THEN
    g_WD_PrevCount := wHeartbeat;
    g_WD_Changed := TRUE;
ELSE
    g_WD_Changed := FALSE;
END_IF;

g_WD_TON(IN := NOT g_WD_Changed, PT := T#500MS);
g_WD_Timeout := g_WD_TON.Q;
g_PC_Ready := bPcReady AND (NOT g_WD_Timeout);

(* 3. EMO — NC접점 반전 + PC 요청 *)
g_EMO_Active := (NOT bEmoInput) OR bPcEmoReq;

(* 4. SafetyStop 판정 *)
g_SafetyStop := g_WD_Timeout OR g_EMO_Active OR (NOT g_PC_Ready);

(* 5. SafetyStop 시 출력 강제 OFF *)
IF g_SafetyStop THEN
    %MW200 := 0;
    %MW201 := 0;
    %MW202 := 0;
    %MW203 := 0;
    %MW204 := 0;
    %MW205 := 0;
    %MW206 := 0;
    %MW207 := 0;
    %MW208 := 0;
    %MW209 := 0;
    g_bStopExec := TRUE;
END_IF;

(* 6. PLC → PC 상태 비트 갱신 (MW501) *)
%MW501 := 0;

IF NOT g_WD_Timeout THEN
    %MW501 := %MW501 OR 16#0001;
END_IF;

IF g_EMO_Active THEN
    %MW501 := %MW501 OR 16#0002;
END_IF;

IF %MW400.1 THEN
    %MW501 := %MW501 OR 16#0004;
END_IF;

IF g_WD_Timeout THEN
    %MW501 := %MW501 OR 16#0008;
END_IF;

%MW501 := %MW501 OR 16#0010;

(* 7. 스캔 카운터 *)
g_ScanCount := g_ScanCount + 1;

