(* ============================================================ *)
(* PROG_SERVO: 서보 모터 제어 (APM 위치결정 FB)                   *)
(* 역할: PC 명령 비트 → APM_xxx FB 실행 → 상태 비트 갱신          *)
(* 위치결정모듈: SLOT=9, AXIS=0 (XBF-PD02A)                      *)
(* 서보 MC 릴레이: PC가 MW200.5 → IO_MAP → %QX0.0.5              *)
(* JOG: PC가 %UW0.9.1 직접 제어 (비트0=CW, 비트1=CCW)            *)
(* ============================================================ *)

(* SafetyStop 시 서보 긴급 정지 *)
IF g_SafetyStop THEN
    bOrgReq := FALSE;
    bDstReq := FALSE;
    bRstReq := FALSE;

    g_FB_Stp(ACTIVE := TRUE, AXIS := 0);

    (* JOG 강제 OFF *)
    wJogWord := %UW0.9.1;
    wJogWord := wJogWord AND 16#FFFC;
    %UW0.9.1 := wJogWord;

    %MW400 := 16#0002;
    %MW401 := 0;
    g_bStopExec := TRUE;

ELSE

    (* 1. PC 명령 비트 읽기 (MW300) *)
    bCmdHome    := %MW300.0;
    bCmdMove    := %MW300.1;
    bCmdStop    := %MW300.4;
    bCmdReset   := %MW300.5;

    (* 제어 부가 비트 (MW301) *)
    bMoveRel    := %MW301.1;

    (* 2. 파라미터 읽기 (MW310~313, DINT = 2 WORD) *)
    dinTargetPos := WORD_TO_DINT(%MW310) + WORD_TO_DINT(%MW311) * 65536;
    dinTargetVel := WORD_TO_DINT(%MW312) + WORD_TO_DINT(%MW313) * 65536;

    (* 3. 수동 엣지 검출 *)
    bEdgeHome   := bCmdHome   AND NOT bPrevHome;
    bEdgeMove   := bCmdMove   AND NOT bPrevMove;
    bEdgeStop   := bCmdStop   AND NOT bPrevStop;
    bEdgeReset  := bCmdReset  AND NOT bPrevReset;

    bPrevHome   := bCmdHome;
    bPrevMove   := bCmdMove;
    bPrevStop   := bCmdStop;
    bPrevReset  := bCmdReset;

    (* 4. 원점복귀 — APM_ORG *)
    IF bEdgeHome THEN
        bOrgReq := TRUE;
    END_IF;

    g_FB_Org(ACTIVE := bOrgReq, AXIS := 0);
    bOrgDone := g_FB_Org.Q;
    bOrgErr  := g_FB_Org.ERR;

    IF bOrgDone OR bOrgErr THEN
        bOrgReq := FALSE;
    END_IF;

    (* 5. 위치 이동 — APM_DST *)
    IF bEdgeMove THEN
        bDstReq := TRUE;
    END_IF;

    g_FB_Dst(ACTIVE := bDstReq, AXIS := 0, DST := dinTargetPos, MSPD := dinTargetVel);
    bDstDone := g_FB_Dst.Q;
    bDstErr  := g_FB_Dst.ERR;

    IF bDstDone OR bDstErr THEN
        bDstReq := FALSE;
    END_IF;

    (* 6. 정지 — APM_STP *)
    IF bEdgeStop THEN
        bStpReq := TRUE;
    END_IF;

    g_FB_Stp(ACTIVE := bStpReq, AXIS := 0);
    bStpDone := g_FB_Stp.Q;

    IF bStpDone THEN
        bStpReq := FALSE;
    END_IF;

    (* 7. 폴트 리셋 — APM_RST *)
    IF bEdgeReset THEN
        bRstReq := TRUE;
    END_IF;

    g_FB_Rst(ACTIVE := bRstReq, AXIS := 0);
    bRstDone := g_FB_Rst.Q;

    IF bRstDone THEN
        bRstReq := FALSE;
    END_IF;

    (* 8. 서보 상태 비트 → MW400 *)
    wStatus := 0;
    wRdyStat := %UW0.9.0;

    (* bit0: 동작 중 *)
    IF bOrgReq OR bDstReq THEN
        wStatus := wStatus OR 16#0001;
    END_IF;
    (* bit1: 에러 발생 *)
    IF bOrgErr OR bDstErr THEN
        wStatus := wStatus OR 16#0002;
    END_IF;
    (* bit4: 위치결정모듈 RDY (비트15) *)
    IF (wRdyStat AND 16#8000) <> 16#0000 THEN
        wStatus := wStatus OR 16#0010;
    END_IF;
    (* bit6: 서보MC 출력 상태 *)
    IF %QX0.0.5 THEN
        wStatus := wStatus OR 16#0040;
    END_IF;

    %MW400 := wStatus;

    (* 9. 명령 응답 비트 → MW401 *)
    wResponse := 0;

    IF bOrgDone THEN
        wResponse := wResponse OR 16#0001;
    END_IF;
    IF bDstDone THEN
        wResponse := wResponse OR 16#0002;
    END_IF;
    IF bOrgErr THEN
        wResponse := wResponse OR 16#0004;
    END_IF;
    IF bDstErr THEN
        wResponse := wResponse OR 16#0008;
    END_IF;
    IF bRstDone THEN
        wResponse := wResponse OR 16#0010;
    END_IF;

    %MW401 := wResponse;

    (* 10. 위치/속도 → MW410~415 (U영역 직접 복사) *)
    %MW410 := %UW0.9.2;   (* 현재 위치 하위 *)
